import{_ as e,a as i,b as o,c as n}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as t,o as r,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Transfer magnet","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/magnet-transfer.md","filePath":"pl-PL/Other/magnet-transfer.md","lastUpdated":1781962217000}'),p={name:"pl-PL/Other/magnet-transfer.md"};function s(u,a,z,m,w,c){return r(),d("div",null,[...a[0]||(a[0]=[l('<h1 id="transfer-magnet" tabindex="-1">Transfer magnet <a class="header-anchor" href="#transfer-magnet" aria-label="Permalink to &quot;Transfer magnet&quot;">​</a></h1><p>Transfer magnet pobiera pliki z linku magnet i automatycznie przesyła je do wybranego kanału chmurowego.</p><p>Przydaje się do przenoszenia odcinków anime, wideo, archiwów i podobnych plików. Wklejasz link magnet, a ImgBed tworzy zadanie pobierania w tle. Po zakończeniu pobierania plik jest przesyłany do ImgBed, a finalny link pojawia się na liście uploadów.</p><p><img src="'+e+'" alt="Transfer magnet" loading="lazy"></p><h2 id="gdzie-uzywac" tabindex="-1">Gdzie używać <a class="header-anchor" href="#gdzie-uzywac" aria-label="Permalink to &quot;Gdzie używać&quot;">​</a></h2><p>Wejście transferu magnet znajduje się w obszarze uploadu na stronie głównej.</p><p>Wklej link magnet do pola, wybierz <code>Transfer</code>, a potem prześlij.</p><p><img src="'+i+'" alt="Upload anime" loading="lazy"></p><h2 id="przed-pierwszym-uzyciem" tabindex="-1">Przed pierwszym użyciem <a class="header-anchor" href="#przed-pierwszym-uzyciem" aria-label="Permalink to &quot;Przed pierwszym użyciem&quot;">​</a></h2><p>Najpierw skonfiguruj transfer magnet w panelu administracyjnym.</p><p>Zwykle potrzebujesz:</p><ol><li>Konta GitHub do uruchamiania zadania pobierania.</li><li>Kanału uploadu w chmurze, np. Google Drive lub OneDrive.</li><li>Docelowego katalogu uploadu.</li><li>Limitu czasu zadania.</li></ol><p>Po przygotowaniu ustawień wróć na stronę główną i wklej link magnet, aby rozpocząć transfer.</p><h2 id="przesyłanie-linku-magnet" tabindex="-1">Przesyłanie linku magnet <a class="header-anchor" href="#przesyłanie-linku-magnet" aria-label="Permalink to &quot;Przesyłanie linku magnet&quot;">​</a></h2><ol><li>Wklej link magnet w polu uploadu na stronie głównej.</li><li>Upewnij się, że tryb to <code>Transfer</code>.</li><li>Kliknij upload.</li><li>Poczekaj, aż ImgBed utworzy zadanie magnet.</li><li>Po uruchomieniu zadania użyj pływającego panelu <code>Magnet Tasks</code> w prawym dolnym rogu, aby śledzić postęp.</li></ol><p>Pobieranie i upload mogą zająć czas. Szybkość zależy od zasobu magnet, środowiska runtime GitHub i wybranego kanału chmurowego.</p><p><img src="'+o+'" alt="Magnet w trakcie pobierania" loading="lazy"></p><h2 id="po-zakonczeniu" tabindex="-1">Po zakończeniu <a class="header-anchor" href="#po-zakonczeniu" aria-label="Permalink to &quot;Po zakończeniu&quot;">​</a></h2><p>Po ukończeniu zadania lista uploadów pokazuje nazwę pliku i link.</p><p>Wideo pokazuje podgląd wideo, obrazy pokazują podgląd obrazu, a inne pliki zwykłą ikonę pliku.</p><p><img src="'+n+'" alt="Pobrane wideo" loading="lazy"></p><p>Możesz skopiować:</p><table tabindex="0"><thead><tr><th>Typ linku</th><th>Zastosowanie</th></tr></thead><tbody><tr><td>Link oryginalny</td><td>Bezpośredni dostęp do pliku</td></tr><tr><td>Markdown</td><td>Wpisy lub notatki Markdown</td></tr><tr><td>HTML</td><td>Kod strony WWW</td></tr><tr><td>BBCode</td><td>Fora obsługujące BBCode</td></tr></tbody></table><h2 id="panel-zadan-magnet" tabindex="-1">Panel zadań magnet <a class="header-anchor" href="#panel-zadan-magnet" aria-label="Permalink to &quot;Panel zadań magnet&quot;">​</a></h2><p>Panel w prawym dolnym rogu pokazuje liczbę zadań, nazwę zadania, postęp i status końcowy.</p><p>Typowe statusy:</p><table tabindex="0"><thead><tr><th>Status</th><th>Znaczenie</th></tr></thead><tbody><tr><td>Waiting</td><td>Zadanie zostało utworzone i czeka na uruchomienie.</td></tr><tr><td>Downloading</td><td>Zasób magnet jest pobierany.</td></tr><tr><td>Uploading</td><td>Plik został pobrany i jest przesyłany do chmury.</td></tr><tr><td>Completed</td><td>Upload się udał i link można skopiować.</td></tr><tr><td>Failed</td><td>Zadanie nie zakończyło się poprawnie. Sprawdź komunikat i spróbuj ponownie.</td></tr></tbody></table><h2 id="wskazowki" tabindex="-1">Wskazówki <a class="header-anchor" href="#wskazowki" aria-label="Permalink to &quot;Wskazówki&quot;">​</a></h2><ul><li>Jeśli link magnet zawiera wiele plików, ImgBed priorytetowo pokazuje główny ukończony plik.</li><li>Duże pliki trwają dłużej. Poczekaj na zakończenie zadania przed odświeżeniem strony.</li><li>Jeśli zasób magnet nie ma dostępnych peerów, może być bardzo wolny albo się nie udać.</li><li>Jeśli konto chmurowe nie ma miejsca, autoryzacja wygasła albo katalog uploadu jest błędny, zadanie może się nie udać.</li><li>Podgląd wideo może potrzebować kilku sekund po zakończeniu uploadu.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="nic-sie-nie-dzieje-po-wklejeniu-linku-magnet" tabindex="-1">Nic się nie dzieje po wklejeniu linku magnet <a class="header-anchor" href="#nic-sie-nie-dzieje-po-wklejeniu-linku-magnet" aria-label="Permalink to &quot;Nic się nie dzieje po wklejeniu linku magnet&quot;">​</a></h3><p>Upewnij się, że transfer magnet jest włączony w panelu administracyjnym oraz że wybrano działające konto GitHub i kanał chmurowy.</p><h3 id="pobieranie-zawsze-jest-wolne" tabindex="-1">Pobieranie zawsze jest wolne <a class="header-anchor" href="#pobieranie-zawsze-jest-wolne" aria-label="Permalink to &quot;Pobieranie zawsze jest wolne&quot;">​</a></h3><p>Szybkość magnet zależy od samego zasobu. Jeśli nie ma dostępnych peerów, pobieranie może być bardzo wolne albo niemożliwe.</p><h3 id="po-uploadzie-nie-ma-podgladu" tabindex="-1">Po uploadzie nie ma podglądu <a class="header-anchor" href="#po-uploadzie-nie-ma-podgladu" aria-label="Permalink to &quot;Po uploadzie nie ma podglądu&quot;">​</a></h3><p>Najpierw sprawdź, czy link pliku się otwiera. Pliki wideo mogą potrzebować chwili, aby załadować się w przeglądarce; możesz też otworzyć link bezpośrednio.</p><h3 id="co-sprawdzic-jesli-zadanie-sie-nie-uda" tabindex="-1">Co sprawdzić, jeśli zadanie się nie uda? <a class="header-anchor" href="#co-sprawdzic-jesli-zadanie-sie-nie-uda" aria-label="Permalink to &quot;Co sprawdzić, jeśli zadanie się nie uda?&quot;">​</a></h3><p>Sprawdź, czy link magnet jest poprawny, czy kanał chmurowy działa i czy katalog uploadu jest prawidłowy. Następnie wyślij zadanie ponownie.</p>',38)])])}const g=t(p,[["render",s]]);export{h as __pageData,g as default};
